Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: create a handler that returns a canned response
    private static HttpClient CreateMockClient(
        HttpStatusCode status, string content)
    {
        var handler = new MockHandler(status, content);
        return new HttpClient(handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        using var client = CreateMockClient(
            HttpStatusCode.InternalServerError, "");
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation ---

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data");
        var fetcher = new DataFetcher(client);
        var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        var cts = new CancellationTokenSource();
        // Handler cancels the token mid-flight
        var handler = new CallbackHandler(() => cts.Cancel());
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via CancellationToken ---

    [TestMethod]
    public async Task FetchAsync_Throws_OnTimeout()
    {
        // Handler that delays longer than the timeout
        var handler = new DelayHandler(TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test helpers (no external mocking library needed) ---

    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _status;
        private readonly string _content;

        public MockHandler(HttpStatusCode status, string content)
        {
            _status = status;
            _content = content;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct)
        {
            ct.ThrowIfCancellationRequested();
            var resp = new HttpResponseMessage(_status)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(resp);
        }
    }

    private class DelayHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct)
        {
            await Task.Delay(_delay, ct); // throws if cancelled
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }

    private class CallbackHandler : HttpMessageHandler
    {
        private readonly Action _onSend;
        public CallbackHandler(Action onSend) => _onSend = onSend;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct)
        {
            _onSend();
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        }
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`** — no external libraries needed; gives full control over `SendAsync`.
- **Pre-cancelled token** — tests that cancellation is checked eagerly.
- **Mid-flight cancellation** — `CallbackHandler` fires `cts.Cancel()` inside `SendAsync`.
- **Timeout** — use `new CancellationTokenSource(timeout)` with a `DelayHandler`; keep the timeout short (50ms) so tests stay fast.
- **MSTest async** — just return `async Task`; the runner handles awaiting. No need for `.Result` or `.GetAwaiter()`.
